import React, { Component } from "react";
import "./App.css";

import PickBehaviour from "./components/PickBehaviour/PickBehaviour";
import PickLook from "./components/PickLook/PickLook";

export default class App extends Component {
  state = {
    statusSave: false,
    pickBehaviour: null,
    pickLook: null,
  };

  componentDidMount() {
    const _this = this;

    window.chrome.storage.sync.get((d) => {
      if (d.hasOwnProperty("optionsFromColorPicker")) {
        _this.setState({
          pickBehaviour: d.optionsFromColorPicker.options.pickBehaviour,
          pickLook: d.optionsFromColorPicker.options.pickLook,
        });
      }
    });
  }

  editOptions = (label, items) => {
    if (label === "pickBehaviour") {
      this.setState({
        pickBehaviour: items,
      });
    } else if (label === "pickLook") {
      this.setState({
        pickLook: items,
      });
    }
  };

  clickOnCHShtct = () => {
    window.chrome.tabs.create({
      url: "chrome://extensions/shortcuts",
    });
  };

  clickOnSave = () => {
    this.setState(
      {
        statusSave: !this.state.statusSave,
      },
      this.offStatus(),

      window.chrome.storage.sync.set({
        optionsFromColorPicker: {
          options: this.state,
        },
      }),

      window.chrome.runtime.sendMessage({
        action: "updateStatusNotiAndContext",
        status: {
          noti: this.state.pickLook.colorNotificatios,
          context: this.state.pickBehaviour.rightClickCopy,
          autoCopy: this.state.pickBehaviour.autoCopy,
        },
      })
    );
  };

  offStatus = () => {
    setTimeout(() => {
      this.setState({
        statusSave: !this.state.statusSave,
      });
    }, 1500);
  };

  render() {
    const { pickBehaviour, pickLook } = this.state;

    return (
      <div className="App">
        {pickBehaviour === null ? null : (
          <PickBehaviour
            getOptions={this.editOptions}
            options={pickBehaviour}
          />
        )}

        {pickLook === null ? null : (
          <PickLook getOptions={this.editOptions} options={pickLook} />
        )}

        <div className="Shortcuts">
          <div className="Shortcuts_Header">
            Keyboard Shortcuts for Pick Color from Web Page
          </div>
          <div className="Shortcuts_Main">
            <div className="Shortcuts_Main_Item">
              <div className="Shortcuts_Main_Item_Header">
                Pickup Color:<div>Alt+R</div>
              </div>
              <p className="Shortcuts_Main_Item_Text">
                You can change this shortcut at Chrome's
                <span onClick={this.clickOnCHShtct}>Extensions Shortcut</span>
                page.
              </p>
            </div>
            <div className="Shortcuts_Main_Item">
              <div className="Shortcuts_Main_Item_Header">
                Cancel Pick:<div>Esc</div>
              </div>
              <p className="Shortcuts_Main_Item_Text">
                Simply cancel active picking color from web page. No color will
                be stored in history.
              </p>
            </div>
            <div className="Shortcuts_Main_Item">
              <div className="Shortcuts_Main_Item_Header">
                Update Colors:<div>U</div>
              </div>
              <p className="Shortcuts_Main_Item_Text">
                Color Picker shows you only color which was present at moment of
                color pick active. If any javascript event occures (hover
                effect, menu appears) you can refresh its "cache" with this
                keyboard shortcut.
              </p>
            </div>
          </div>
        </div>
        <div className="Footer_Header"></div>
        <button className="SaveSettings" onClick={this.clickOnSave}>
          Save settings
        </button>
        <span className={this.state.statusSave === false ? "off" : "on"}>
          Options saved
        </span>
      </div>
    );
  }
}
