import React, { Component } from "react";

export default class PickLook extends Component {
  state = {
    colorNotificatios: this.props.options.colorNotificatios,
  };

  handleInputChange = (e) => {
    const value =
      e.target.type === "checkbox" ? e.target.checked : e.target.value;
    const name = e.target.name;

    this.setState(
      {
        [name]: value,
      },
      () => {
        this.props.getOptions("pickLook", this.state);
      }
    );
  };

  render() {
    return (
      <div className="PickLook">
        <div className="PickLook_Header">Webpage Notification</div>
        <div className="PickLook_Main">
          <div className="PickLook_Main_Item">
            <label>
              <input
                className="PickLook_Main_Input"
                name="colorNotificatios"
                type="checkbox"
                checked={this.state.colorNotificatios}
                onChange={this.handleInputChange}
              />
              Enable notification when choosing a color on a page
            </label>
          </div>
        </div>
      </div>
    );
  }
}
