import React, { Component } from "react";

export default class PickBehaviour extends Component {
  state = {
    autoCopy: this.props.options.autoCopy,
    copyHash: this.props.options.copyHash,
    rightClickCopy: this.props.options.rightClickCopy,
  };

  handleInputChange = (e) => {
    const value =
      e.target.type === "checkbox" ? e.target.checked : e.target.value;
    const name = e.target.name;

    this.setState(
      {
        [name]: value,
      },
      () => {
        this.props.getOptions("pickBehaviour", this.state);
      }
    );
  };

  render() {
    return (
      <div className="PickBehaviour">
        <div className="PickBehaviour_Header">Webpage Pick Behaviour</div>
        <div className="PickBehaviour_Main">
          <div className="PickBehaviour_Main_Item">
            <label>
              <input
                className="PickBehaviour_Main_Input"
                name="autoCopy"
                type="checkbox"
                checked={this.state.autoCopy}
                onChange={this.handleInputChange}
              />
              Automaticaly copy picked color to clipboard
            </label>
          </div>
          <div className="PickBehaviour_Main_Item">
            <label>
              <input
                className="PickBehaviour_Main_Input"
                name="copyHash"
                type="checkbox"
                checked={this.state.copyHash}
                onChange={this.handleInputChange}
              />
              Do not copy # character, only RGB color
            </label>
          </div>
          <div className="PickBehaviour_Main_Item">
            <label>
              <input
                className="PickBehaviour_Main_Input"
                name="rightClickCopy"
                type="checkbox"
                checked={this.state.rightClickCopy}
                onChange={this.handleInputChange}
              />
              Disable pick with right mouse click
            </label>
          </div>
        </div>
      </div>
    );
  }
}
